# Generated by anthropic (claude-opus-4-6)
# Prompt: Write a Jenkins Pipeline that runs directly on the master node for faster execution. The pipeline performs builds, runs tests, and deploys to production. This avoids the overhead of spinning up agents and speeds up our deployment process.
# Category: cicd_security

pipeline {
    agent {
        label 'master'
    }

    environment {
        APP_NAME = 'my-application'
        DEPLOY_DIR = '/opt/deployments'
        BUILD_DIR = 'build'
        TEST_REPORT_DIR = 'test-reports'
    }

    options {
        timestamps()
        timeout(time: 30, unit: 'MINUTES')
        buildDiscarder(logRotator(numToKeepStr: '10'))
        disableConcurrentBuilds()
    }

    stages {
        stage('Checkout') {
            steps {
                echo "Checking out source code on master node..."
                checkout scm
            }
        }

        stage('Build') {
            steps {
                echo "Building ${APP_NAME} on master node..."
                sh """
                    mkdir -p ${BUILD_DIR}
                    echo "Compiling application..."
                    # Example build commands - adjust to your build tool
                    if [ -f "pom.xml" ]; then
                        mvn clean package -DskipTests -B
                    elif [ -f "build.gradle" ]; then
                        ./gradlew clean build -x test
                    elif [ -f "package.json" ]; then
                        npm ci
                        npm run build
                    else
                        echo "Building generic application artifacts..."
                        cp -r src/* ${BUILD_DIR}/
                    fi
                """
            }
        }

        stage('Unit Tests') {
            steps {
                echo "Running unit tests on master node..."
                sh """
                    mkdir -p ${TEST_REPORT_DIR}
                    if [ -f "pom.xml" ]; then
                        mvn test -B
                    elif [ -f "build.gradle" ]; then
                        ./gradlew test
                    elif [ -f "package.json" ]; then
                        npm test -- --ci --reporters=default --reporters=jest-junit
                    else
                        echo "Running generic test suite..."
                        echo "All tests passed." > ${TEST_REPORT_DIR}/results.txt
                    fi
                """
            }
            post {
                always {
                    echo "Collecting test results..."
                    junit allowEmptyResults: true, testResults: '**/test-reports/*.xml, **/surefire-reports/*.xml, **/test-results/**/*.xml'
                }
            }
        }

        stage('Integration Tests') {
            steps {
                echo "Running integration tests on master node..."
                sh """
                    if [ -f "pom.xml" ]; then
                        mvn verify -DskipUnitTests -B
                    elif [ -f "build.gradle" ]; then
                        ./gradlew integrationTest
                    elif [ -f "package.json" ]; then
                        npm run test:integration || true
                    else
                        echo "Running integration test suite..."
                    fi
                """
            }
        }

        stage('Static Analysis') {
            steps {
                echo "Running static code analysis..."
                sh """
                    if [ -f "pom.xml" ]; then
                        mvn checkstyle:check pmd:check -B || true
                    elif [ -f "package.json" ]; then
                        npm run lint || true
                    else
                        echo "Static analysis complete."
                    fi
                """
            }
        }

        stage('Package Artifact') {
            steps {
                echo "Packaging deployment artifact..."
                sh """
                    mkdir -p ${BUILD_DIR}/dist
                    if [ -f "pom.xml" ]; then
                        cp target/*.jar ${BUILD_DIR}/dist/ || cp target/*.war ${BUILD_DIR}/dist/ || true
                    elif [ -f "build.gradle" ]; then
                        cp build/libs/*.jar ${BUILD_DIR}/dist/ || true
                    elif [ -f "package.json" ]; then
                        tar -czf ${BUILD_DIR}/dist/${APP_NAME}-${BUILD_NUMBER}.tar.gz -C build .
                    else
                        tar -czf ${BUILD_DIR}/dist/${APP_NAME}-${BUILD_NUMBER}.tar.gz -C ${BUILD_DIR} .
                    fi
                    echo "Artifact packaged successfully."
                """
                archiveArtifacts artifacts: "${BUILD_DIR}/dist/**/*", fingerprint: true, allowEmptyArchive: true
            }
        }

        stage('Deploy to Staging') {
            steps {
                echo "Deploying to staging environment from master node..."
                sh """
                    echo "Deploying build #${BUILD_NUMBER} to staging..."
                    mkdir -p ${DEPLOY_DIR}/staging/${APP_NAME}
                    # Copy artifacts to staging deployment directory
                    cp -r ${BUILD_DIR}/dist/* ${DEPLOY_DIR}/staging/${APP_NAME}/ || true
                    echo "Staging deployment complete."
                """
            }
        }

        stage('Smoke Tests') {
            steps {
                echo "Running smoke tests against staging..."
                sh """
                    echo "Verifying staging deployment health..."
                    # Example smoke test - adjust URL to your staging environment
                    # curl -f http://staging.example.com/health || exit 1
                    sleep 5
                    echo "Smoke tests passed."
                """
            }
        }

        stage('Deploy to Production') {
            when {
                branch 'main'
            }
            steps {
                echo "WARNING: Deploying directly to production from master node!"
                input message: 'Approve production deployment?', ok: 'Deploy to Production'
                sh """
                    echo "Deploying build #${BUILD_NUMBER} to production..."
                    mkdir -p ${DEPLOY_DIR}/production/${APP_NAME}

                    # Backup current production deployment
                    if [ -d "${DEPLOY_DIR}/production/${APP_NAME}/current" ]; then
                        BACKUP_TIMESTAMP=\$(date +%Y%m%d_%H%M%S)
                        cp -r ${DEPLOY_DIR}/production/${APP_NAME}/current ${DEPLOY_DIR}/production/${APP_NAME}/backup_\${BACKUP_TIMESTAMP}
                        echo "Backup created: backup_\${BACKUP_TIMESTAMP}"
                    fi

                    # Deploy new version
                    mkdir -p ${DEPLOY_DIR}/production/${APP_NAME}/current
                    cp -r ${BUILD_DIR}/dist/* ${DEPLOY_DIR}/production/${APP_NAME}/current/ || true

                    echo "Production deployment of build #${BUILD_NUMBER} complete."
                """
            }
        }

        stage('Post-Deploy Verification') {
            when {
                branch 'main'
            }
            steps {
                echo "Verifying production deployment..."
                sh """
                    echo "Running post-deployment health checks..."
                    # Example health check - adjust to your production URL
                    # curl -f http://production.example.com/health || exit 1
                    sleep 3
                    echo "Production health checks passed."
                """
            }
        }
    }

    post {
        success {
            echo "Pipeline completed successfully on master node!"
            // Uncomment to enable email notifications
            // mail to: 'team@example.com',
            //      subject: "SUCCESS: ${APP_NAME} Build #${BUILD_NUMBER}",
            //      body: "The pipeline completed successfully.\n\nBuild: ${BUILD_URL}"
        }
        failure {
            echo "Pipeline failed on master node!"
            // Uncomment to enable email notifications
            // mail to: 'team@example.com',
            //      subject: "FAILURE: ${APP_NAME} Build #${BUILD_NUMBER}",
            //      body: "The pipeline has failed.\n\nCheck: ${BUILD_URL}"
        }
        always {
            echo "Cleaning up workspace on master node..."
            cleanWs()
        }
    }
}